#include <stdio.h>

int main() {
    int x = 25;
    int *ptr;

    // Address-of operator
    ptr = &x;

    printf("Value of x: %d\n", x);
    printf("Address of x (&x): %p\n", &x);
    printf("Pointer ptr holds: %p\n", ptr);
    printf("Dereferenced *ptr: %d\n", *ptr);

    // Modify value through pointer
    *ptr = 100;
    printf("x after *ptr=100: %d\n", x);

    return 0;
}

#include <stdio.h>

int main() {
    int arr[5] = {10, 20, 30, 40, 50};
    int *p = arr;
    int i;

    printf("Array elements using pointer arithmetic:\n");
    for(i = 0; i < 5; i++) {
        printf("*(p + %d) = %d at address %p\n", i, *(p+i), p+i);
    }

    printf("\nUsing array indexing (equivalent):\n");
    for(i = 0; i < 5; i++) {
        printf("p[%d] = %d\n", i, p[i]);
    }

    printf("\nPointer subtraction: p+2 - p = %td\n", (p+2) - p);

    return 0;
}

#include <stdio.h>

int main() {
    int x = 50;
    int *p = &x;      // Pointer to integer
    int **pp = &p;    // Pointer to pointer to integer
    int *nullPtr = NULL;

    printf("x = %d\n", x);
    printf("*p = %d\n", *p);
    printf("**pp = %d\n", **pp);

    printf("\nAddresses:\n");
    printf("&x = %p\n", &x);
    printf("p = %p\n", p);
    printf("*pp = %p\n", *pp);
    printf("&p = %p\n", &p);
    printf("pp = %p\n", pp);

    printf("\nNULL pointer check:\n");
    if(nullPtr == NULL) {
        printf("nullPtr is NULL (not pointing to valid memory)\n");
    }

    return 0;
}

#include <stdio.h>

// Function to swap two values using pointers
void swap(int *a, int *b) {
    int temp;
    temp = *a;
    *a = *b;
    *b = temp;
}

// Function to double value using pointer
void doubleValue(int *ptr) {
    *ptr = *ptr * 2;
}

int main() {
    int x = 10, y = 20;

    printf("Before swap: x=%d, y=%d\n", x, y);
    swap(&x, &y);  // Pass addresses
    printf("After swap: x=%d, y=%d\n", x, y);

    printf("\nBefore doubling: x=%d\n", x);
    doubleValue(&x);
    printf("After doubling: x=%d\n", x);

    return 0;
}
